function getTableHeight() {
    var top = document.getElementById("example-table").getBoundingClientRect().top;
    var available = window.innerHeight - top - 10;
    return Math.max(350, available) + "px";
}



function formatoCorrectoIncorrecto(cell){
    var v = cell.getValue();

    if (v == 0) {
        return "<span class='estado-ok'>✓ CORRECTO</span>";
    }
