function editorSiNo(cell, onRendered, success, cancel){
    var editor = document.createElement("select");
    editor.style.width = "100%";
    editor.style.boxSizing = "border-box";

    var optBlank = document.createElement("option");
    optBlank.value = "";
    optBlank.text = "PENDIENTE";
    editor.appendChild(optBlank);

    var opt0 = document.createElement("option");
    opt0.value = "0";
    opt0.text = "CORRECTO";
    editor.appendChild(opt0);

    var opt1 = document.createElement("option");
    opt1.value = "1";
    opt1.text = "INCORRECTO";
    editor.appendChild(opt1);

    editor.value = cell.getValue() == null ? "" : String(cell.getValue());

    onRendered(function(){
        editor.focus();
    });

    editor.addEventListener("change", function(){
        success(editor.value);
    });

    editor.addEventListener("blur", function(){
        success(editor.value);
    });

    return editor;
}



