function collapseDetail(row){
    var rowEl = row.getElement();
    var next = rowEl.nextSibling;

    if (next && next.classList && next.classList.contains("detail-row-holder")) {
        next.remove();
    }

    rowEl.setAttribute("data-expanded", "0");

    var btn = rowEl.querySelector(".btn-expand-row");
    if (btn) {
        btn.innerHTML = "+";
    }
}

function formatoVerificacionAddon(cell){
    var v = cell.getValue();

    if (v == 1) {
        return "<span class='estado-ok'>✓ SI</span>";
    }
    if (v == 0) {
        return "<span class='estado-error'>✗ NO</span>";
    }

    return "<span class='estado-alerta'>PENDIENTE</span>";
}

