function getColumnState() {
    return table.getColumns().map(function(col, index){
        var def = col.getDefinition();
        return {
            field: def.field || "__col_" + index,
            title: def.title || "",
            visible: col.isVisible()
        };
    });
}

function saveColumnState() {
    var state = getColumnState();
    localStorage.setItem("ventas_tabulator_state", JSON.stringify(state));
    console.log("estado guardado:", state);
}

function restoreColumnState() {
    var saved = localStorage.getItem("ventas_tabulator_state");
    if (!saved) {
        console.log("no hay estado guardado");
        return;
    }

    try {
        var state = JSON.parse(saved);
        if (!Array.isArray(state) || !state.length) {
            return;
        }

        state.forEach(function(item){
            var col = table.getColumn(item.field);
            if (!col) return;

            if (item.visible) {
                col.show();
            } else {
                col.hide();
            }
        });

        for (var i = 0; i < state.length; i++) {
            var item = state[i];
            var col = table.getColumn(item.field);
            if (!col) continue;

            var colsNow = table.getColumns();
            var targetCol = colsNow[i];

            if (!targetCol) continue;
            if (col === targetCol) continue;

            table.moveColumn(col, targetCol, false);
        }

        console.log("estado restaurado:", state);

    } catch(e) {
        console.error("No se pudo restaurar estado de columnas:", e);
    }
}

setTimeout(function(){
    restoreColumnState();
    table.redraw(true);
}, 50);

table.on("columnMoved", function(){
    saveColumnState();
});

table.on("columnVisibilityChanged", function(){
    saveColumnState();
});








function buildColumnsMenu() {
    var menu = document.getElementById("columns-menu");
    menu.innerHTML = "";

    table.getColumns().forEach(function(col){
        var def = col.getDefinition();
        if (!def.title || def.title === "") return;

        var label = document.createElement("label");
        var checkbox = document.createElement("input");
        checkbox.type = "checkbox";
        checkbox.checked = col.isVisible();

        checkbox.addEventListener("change", function(){
            if (this.checked) {
                col.show();
            } else {
                col.hide();
            }
        });

        label.appendChild(checkbox);
        label.appendChild(document.createTextNode(def.title));
        menu.appendChild(label);
    });
}

document.getElementById("toggle-columns-btn").addEventListener("click", function(e){
    var menu = document.getElementById("columns-menu");

    if (menu.style.display === "none" || menu.style.display === "") {
        buildColumnsMenu();
        menu.style.display = "block";
        menu.style.left = e.pageX + "px";
        menu.style.top = (e.pageY + 5) + "px";
    } else {
        menu.style.display = "none";
    }
});

document.addEventListener("click", function(e){
    var menu = document.getElementById("columns-menu");
    var btn = document.getElementById("toggle-columns-btn");

    if (!menu.contains(e.target) && e.target !== btn) {
        menu.style.display = "none";
    }
});

