    color: #FFFFFF !important; 
}

/* Si dentro del panel-title hay un enlace (Ej. si el encabezado permite colapsar/expandir 
   y el título es un <a>), también debemos forzar el color del enlace.
*/
.panel-heading .panel-title a {
    color: #FFFFFF !important;
}

/* Asegurar que el texto dentro del panel-title no se vea afectado por reglas generales
   que usen el estado 'modal-open' en el cuerpo de la página.
*/
.modal-open .panel-heading .panel-title {
    color: #FFFFFF !important;
}

/* Evita encogimiento general */
#center_block, .rnr-page, .bs-body { min-height: 85vh; }

/* Botón flotante "Alta rápida" sobre el modal del lookup (fallback cross-origin) */
.lkp-floating-add {
  position: fixed;
  right: 24px;
  top: 24px;
  z-index: 2147483000;
  padding: 10px 14px;
  border-radius: 12px;
  background: #0d6efd;
  color: #fff;
  font-weight: 600;
  cursor: pointer;
  display: none; /* se activa por JS cuando detectamos el iframe del lookup */
  box-shadow: 0 6px 20px rgba(0,0,0,.25);
}

/* Portal del ADD en el top.document */
#lkpAddPortal {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,.35);
  z-index: 2147483647;
  display: none;
}
#lkpAddPortal .shell {
  position: absolute;
  inset: 3vh 3vw;           /* 94% del viewport */
  background: #fff;
  border-radius: 16px;
  box-shadow: 0 20px 60px rgba(0,0,0,.4);
  overflow: hidden;
}
#lkpAddPortal iframe {
  width: 100%;
  height: 100%;
  border: 0;
  display: block;
}
#lkpAddPortal .close-btn {
  position: absolute;
  top: 10px; right: 10px;
  z-index: 10;
  padding: 6px 10px;
  background: #111;
  color: #fff;
  border-radius: 10px;
  cursor: pointer;
  font-weight: 600;
  opacity: .85;
}
#lkpAddPortal .close-btn:hover { opacity: 1; }

